module pitch_detection(  
    input clk,  
    input rst,  
    input [9:0] frequency,  
    input [9:0] threshold,  
    output reg pitch_detected  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            pitch_detected <= 0;  
        else  
            pitch_detected <= (frequency > threshold) ? 1 : 0;  
    end  
endmodule
